Amazon EKS Bottlerocket and Fargate # Amazon EKS Before starting with the main content, it&rsquo;s necessary to provision the Amazon EKS in AWS.
Requirements # If you would like to follow this documents and it&rsquo;s task you will need to set up few environment variables.
The LETSENCRYPT_ENVIRONMENT variable should be one of:
staging - Let&rsquo;s Encrypt will create testing certificate (not valid) production - Let&rsquo;s Encrypt will create valid certificate (use with care) BASE_DOMAIN contains DNS records for all your Kubernetes clusters. The cluster names will look like CLUSTER_NAME.BASE_DOMAIN (kube1.k8s.mylabs.dev).
# Hostname / FQDN definitions export BASE_DOMAIN=${BASE_DOMAIN:-k8s.mylabs.dev} export CLUSTER_NAME=${CLUSTER_NAME:-kube1} export CLUSTER_FQDN=&#34;${CLUSTER_NAME}.${BASE_DOMAIN}&#34; export KUBECONFIG=${PWD}/kubeconfig-${CLUSTER_NAME}.conf # * &#34;production&#34; - valid certificates signed by Lets Encrypt &#34;&#34; # * &#34;staging&#34; - not trusted certs signed by Lets Encrypt &#34;Fake LE Intermediate X1&#34; export LETSENCRYPT_ENVIRONMENT=&#34;staging&#34; export LETSENCRYPT_CERTIFICATE=&#34;https://letsencrypt.org/certs/staging/letsencrypt-stg-root-x1.pem&#34; # export LETSENCRYPT_ENVIRONMENT=&#34;production&#34; # export LETSENCRYPT_CERTIFICATE=&#34;https://letsencrypt.org/certs/lets-encrypt-r3.pem&#34; export MY_EMAIL=&#34;petr.ruzicka@gmail.com&#34; # GitHub Organization + Team where are the users who will have the admin access # to K8s resources (Grafana). Only users in GitHub organization # (MY_GITHUB_ORG_NAME) will be able to access the apps via ingress. export MY_GITHUB_ORG_NAME=&#34;ruzickap-org&#34; export MY_GITHUB_USERNAME=&#34;ruzickap&#34; # AWS Region export AWS_DEFAULT_REGION=&#34;eu-west-1&#34; export SLACK_CHANNEL=&#34;mylabs&#34; # Tags used to tag the AWS resources export TAGS=&#34;Owner=${MY_EMAIL} Environment=Dev Group=Cloud_Native Squad=Cloud_Container_Platform compliance:na:defender=bottlerocket&#34; echo -e &#34;${MY_EMAIL} | ${LETSENCRYPT_ENVIRONMENT} | ${CLUSTER_NAME} | ${BASE_DOMAIN} | ${CLUSTER_FQDN}\n${TAGS}&#34; Prepare GitHub OAuth &ldquo;access&rdquo; credentials ans AWS &ldquo;access&rdquo; variables.
You will need to configure AWS CLI: Configuring the AWS CLI
# Common password export MY_PASSWORD=&#34;xxxx&#34; # AWS Credentials export AWS_ACCESS_KEY_ID=&#34;&#34; export AWS_SECRET_ACCESS_KEY=&#34;&#34; export AWS_CONSOLE_ADMIN_ROLE_ARN=&#34;arn:aws:iam::7xxxxxxxxxx7:role/xxxxxxxxxxxxxN&#34; # GitHub Organization OAuth Apps credentials export MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID=&#34;3xxxxxxxxxxxxxxxxxx3&#34; export MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET=&#34;7xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx8&#34; export MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID=&#34;4xxxxxxxxxxxxxxxxxx4&#34; export MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET=&#34;7xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxa&#34; # Sysdig credentials export SYSDIG_AGENT_ACCESSKEY=&#34;xxx&#34; # Aqua credentials export AQUA_REGISTRY_USERNAME=&#34;xxx&#34; export AQUA_REGISTRY_PASSWORD=&#34;xxx&#34; export AQUA_ENFORCER_TOKEN=&#34;xxx&#34; # Splunk credentials export SPLUNK_HOST=&#34;xxx&#34; export SPLUNK_TOKEN=&#34;xxx&#34; export SPLUNK_INDEX_NAME=&#34;xxx&#34; # Slack incoming webhook export SLACK_INCOMING_WEBHOOK_URL=&#34;https://hooks.slack.com/services/YOUR/SLACK/WEBHOOK&#34; export SLACK_BOT_API_TOKEN=&#34;xxxx-xxxxxxxxxxxxx-xxxxxxxxxxxxx-xxxxxxxxxxxxxxxxxxxxxxxP&#34; # Okta configuration export OKTA_ISSUER=&#34;https://exxxxxxx-xxxxx-xx.okta.com&#34; export OKTA_CLIENT_ID=&#34;0xxxxxxxxxxxxxxxxxx7&#34; export OKTA_CLIENT_SECRET=&#34;1xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxH&#34; Verify if all the necessary variables were set:
case &#34;${CLUSTER_NAME}&#34; in kube1) MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID=${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID:-${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID_KUBE1}} MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET=${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET:-${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET_KUBE1}} MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID=${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID:-${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID_KUBE1}} MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET=${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET:-${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET_KUBE1}} ;; kube2) MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID=${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID:-${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_ID_KUBE2}} MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET=${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET:-${MY_GITHUB_ORG_OAUTH_DEX_CLIENT_SECRET_KUBE2}} MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID=${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID:-${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_ID_KUBE2}} MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET=${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET:-${MY_GITHUB_ORG_OAUTH_KEYCLOAK_CLIENT_SECRET_KUBE2}} ;; *) echo &#34;Unsupported cluster name: ${CLUSTER_NAME} !&#34; exit 1 ;; esac : &#34;${AWS_ACCESS_KEY_ID?}&#34; : &#34;${AWS_SECRET_ACCESS_KEY?}&#34; : &#34;${AWS_CONSOLE_ADMIN_ROLE_ARN?}&#34; : &#34;${GITHUB_TOKEN?}&#34; : &#34;${SLACK_INCOMING_WEBHOOK_URL?}&#34; : &#34;${SLACK_BOT_API_TOKEN?}&#34; : &#34;${MY_PASSWORD?}&#34; : &#34;${OKTA_ISSUER?}&#34; : &#34;${OKTA_CLIENT_ID?}&#34; : &#34;${OKTA_CLIENT_SECRET?}&#34; Prepare the local working environment # ::: tip You can skip these steps if you have all the required software already installed. :::
Install necessary software:
if command -v apt-get &amp;&gt; /dev/null; then apt update -qq DEBIAN_FRONTEND=noninteractive apt-get install -y -qq apache2-utils ansible dnsutils git gnupg2 jq sudo unzip &gt; /dev/null fi Install AWS CLI binary:
if ! command -v aws &amp;&gt; /dev/null; then curl -sL &#34;https://awscli.amazonaws.com/awscli-exe-linux-x86_64.zip&#34; -o &#34;/tmp/awscliv2.zip&#34; unzip -q -o /tmp/awscliv2.zip -d /tmp/ sudo /tmp/aws/install fi Install kubectl binary:
if ! command -v kubectl &amp;&gt; /dev/null; then # https://github.com/kubernetes/kubectl/releases sudo curl -s -Lo /usr/local/bin/kubectl &#34;https://storage.googleapis.com/kubernetes-release/release/v1.21.1/bin/$(uname | sed &#34;s/./\L&amp;/g&#34; )/amd64/kubectl&#34; sudo chmod a+x /usr/local/bin/kubectl fi Install Helm:
if ! command -v helm &amp;&gt; /dev/null; then # https://github.com/helm/helm/releases curl -s https://raw.githubusercontent.com/helm/helm/master/scripts/get | bash -s -- --version v3.6.0 fi Install eksctl:
if ! command -v eksctl &amp;&gt; /dev/null; then # https://github.com/weaveworks/eksctl/releases curl -s -L &#34;https://github.com/weaveworks/eksctl/releases/download/0.60.0/eksctl_$(uname)_amd64.tar.gz&#34; | sudo tar xz -C /usr/local/bin/ fi Install AWS IAM Authenticator for Kubernetes:
if ! command -v aws-iam-authenticator &amp;&gt; /dev/null; then # https://docs.aws.amazon.com/eks/latest/userguide/install-aws-iam-authenticator.html sudo curl -s -Lo /usr/local/bin/aws-iam-authenticator &#34;https://amazon-eks.s3.us-west-2.amazonaws.com/1.19.6/2021-01-05/bin/$(uname | sed &#34;s/./\L&amp;/g&#34;)/amd64/aws-iam-authenticator&#34; sudo chmod a+x /usr/local/bin/aws-iam-authenticator fi Install vault:
if ! command -v vault &amp;&gt; /dev/null; then curl -s -L &#34;https://releases.hashicorp.com/vault/1.7.2/vault_1.7.2_$(uname | sed &#34;s/./\L&amp;/g&#34;)_amd64.zip&#34; -o /tmp/vault.zip sudo unzip -q /tmp/vault.zip -d /usr/local/bin/ rm /tmp/vault.zip fi Install velero:
if ! command -v velero &amp;&gt; /dev/null; then curl -s -L &#34;https://github.com/vmware-tanzu/velero/releases/download/v1.6.0/velero-v1.6.0-$(uname | sed &#34;s/./\L&amp;/g&#34;)-amd64.tar.gz&#34; -o /tmp/velero.tar.gz sudo tar xzf /tmp/velero.tar.gz -C /usr/local/bin/ --strip-components 1 &#34;velero-v1.6.0-$(uname | sed &#34;s/./\L&amp;/g&#34;)-amd64/velero&#34; fi Install flux:
if ! command -v flux &amp;&gt; /dev/null; then curl -s https://fluxcd.io/install.sh | sudo bash fi Install calicoctl:
if ! command -v calicoctl &amp;&gt; /dev/null; then sudo curl -s -Lo /usr/local/bin/calicoctl https://github.com/projectcalico/calicoctl/releases/download/v3.20.0/calicoctl sudo chmod a+x /usr/local/bin/calicoctl fi Install SOPS: Secrets OPerationS:
if ! command -v sops &amp;&gt; /dev/null; then sudo curl -s -Lo /usr/local/bin/sops &#34;https://github.com/mozilla/sops/releases/download/v3.7.1/sops-v3.7.1.$(uname | sed &#34;s/./\L&amp;/g&#34;)&#34; sudo chmod a+x /usr/local/bin/sops fi Install kustomize:
if ! command -v kustomize &amp;&gt; /dev/null; then curl -s &#34;https://raw.githubusercontent.com/kubernetes-sigs/kustomize/master/hack/install_kustomize.sh&#34; | sudo bash -s 4.1.2 /usr/local/bin/ fi Install hey:
if ! command -v hey &amp;&gt; /dev/null; then sudo curl -s -Lo /usr/local/bin/hey &#34;https://hey-release.s3.us-east-2.amazonaws.com/hey_$(uname | sed &#34;s/./\L&amp;/g&#34;)_amd64&#34; sudo chmod a+x /usr/local/bin/hey fi Configure AWS Route 53 Domain delegation # Create DNS zone (BASE_DOMAIN):
aws route53 create-hosted-zone --output json \ --name &#34;${BASE_DOMAIN}&#34; \ --caller-reference &#34;$(date)&#34; \ --hosted-zone-config=&#34;{\&#34;Comment\&#34;: \&#34;Created by ${MY_EMAIL}\&#34;, \&#34;PrivateZone\&#34;: false}&#34; | jq Use your domain registrar to change the nameservers for your zone (for example &ldquo;mylabs.dev&rdquo;) to use the Amazon Route 53 nameservers. Here is the way how you can find out the the Route 53 nameservers:
NEW_ZONE_ID=$(aws route53 list-hosted-zones --query &#34;HostedZones[?Name==\`${BASE_DOMAIN}.\`].Id&#34; --output text) NEW_ZONE_NS=$(aws route53 get-hosted-zone --output json --id &#34;${NEW_ZONE_ID}&#34; --query &#34;DelegationSet.NameServers&#34;) NEW_ZONE_NS1=$(echo &#34;${NEW_ZONE_NS}&#34; | jq -r &#34;.[0]&#34;) NEW_ZONE_NS2=$(echo &#34;${NEW_ZONE_NS}&#34; | jq -r &#34;.[1]&#34;) Create the NS record in k8s.mylabs.dev (BASE_DOMAIN) for proper zone delegation. This step depends on your domain registrar - I&rsquo;m using CloudFlare and using Ansible to automate it:
ansible -m cloudflare_dns -c local -i &#34;localhost,&#34; localhost -a &#34;zone=mylabs.dev record=${BASE_DOMAIN} type=NS value=${NEW_ZONE_NS1} solo=true proxied=no account_email=${CLOUDFLARE_EMAIL} account_api_token=${CLOUDFLARE_API_KEY}&#34; ansible -m cloudflare_dns -c local -i &#34;localhost,&#34; localhost -a &#34;zone=mylabs.dev record=${BASE_DOMAIN} type=NS value=${NEW_ZONE_NS2} solo=false proxied=no account_email=${CLOUDFLARE_EMAIL} account_api_token=${CLOUDFLARE_API_KEY}&#34; Output:
localhost | CHANGED =&gt; { &#34;ansible_facts&#34;: { &#34;discovered_interpreter_python&#34;: &#34;/usr/bin/python&#34; }, &#34;changed&#34;: true, &#34;result&#34;: { &#34;record&#34;: { &#34;content&#34;: &#34;ns-885.awsdns-46.net&#34;, &#34;created_on&#34;: &#34;2020-11-13T06:25:32.18642Z&#34;, &#34;id&#34;: &#34;dxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxb&#34;, &#34;locked&#34;: false, &#34;meta&#34;: { &#34;auto_added&#34;: false, &#34;managed_by_apps&#34;: false, &#34;managed_by_argo_tunnel&#34;: false, &#34;source&#34;: &#34;primary&#34; }, &#34;modified_on&#34;: &#34;2020-11-13T06:25:32.18642Z&#34;, &#34;name&#34;: &#34;k8s.mylabs.dev&#34;, &#34;proxiable&#34;: false, &#34;proxied&#34;: false, &#34;ttl&#34;: 1, &#34;type&#34;: &#34;NS&#34;, &#34;zone_id&#34;: &#34;2xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxe&#34;, &#34;zone_name&#34;: &#34;mylabs.dev&#34; } } } localhost | CHANGED =&gt; { &#34;ansible_facts&#34;: { &#34;discovered_interpreter_python&#34;: &#34;/usr/bin/python&#34; }, &#34;changed&#34;: true, &#34;result&#34;: { &#34;record&#34;: { &#34;content&#34;: &#34;ns-1692.awsdns-19.co.uk&#34;, &#34;created_on&#34;: &#34;2020-11-13T06:25:37.605605Z&#34;, &#34;id&#34;: &#34;9xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxb&#34;, &#34;locked&#34;: false, &#34;meta&#34;: { &#34;auto_added&#34;: false, &#34;managed_by_apps&#34;: false, &#34;managed_by_argo_tunnel&#34;: false, &#34;source&#34;: &#34;primary&#34; }, &#34;modified_on&#34;: &#34;2020-11-13T06:25:37.605605Z&#34;, &#34;name&#34;: &#34;k8s.mylabs.dev&#34;, &#34;proxiable&#34;: false, &#34;proxied&#34;: false, &#34;ttl&#34;: 1, &#34;type&#34;: &#34;NS&#34;, &#34;zone_id&#34;: &#34;2xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxe&#34;, &#34;zone_name&#34;: &#34;mylabs.dev&#34; } } } Add new domain to Route 53, Policies, S3, EBS # Details with examples are described on these links:
https://aws.amazon.com/blogs/opensource/introducing-fine-grained-iam-roles-service-accounts/ https://cert-manager.io/docs/configuration/acme/dns01/route53/ https://github.com/kubernetes-sigs/external-dns/blob/master/docs/tutorials/aws.md Create CloudFormation template containing policies for Route53, S3 access (Harbor, Velero) and Domain. Put new domain CLUSTER_FQDN to the Route 53 and configure the DNS delegation from the BASE_DOMAIN.
mkdir -vp &#34;tmp/${CLUSTER_FQDN}&#34; cat &gt; &#34;tmp/${CLUSTER_FQDN}/aws-route53-iam-s3-kms-asm.yml&#34; &lt;&lt; \EOF Description: &#34;Template to generate the necessary IAM Policies for access to Route53 and S3&#34; Parameters: ClusterFQDN: Description: &#34;Cluster domain where all necessary app subdomains will live (subdomain of BaseDomain). Ex: kube1.k8s.mylabs.dev&#34; Type: String ClusterName: Description: &#34;Cluster Name Ex: kube1&#34; Type: String BaseDomain: Description: &#34;Base domain where cluster domains + their subdomains will live. Ex: k8s.mylabs.dev&#34; Type: String Resources: # This AWS control checks whether the status of the AWS Systems Manager association compliance is COMPLIANT or NON_COMPLIANT after the association is executed on an instance. ConfigRule: Type: &#34;AWS::Config::ConfigRule&#34; Properties: ConfigRuleName: !Sub &#34;${ClusterName}-ec2-managedinstance-association-compliance-status-check&#34; Scope: ComplianceResourceTypes: - &#34;AWS::SSM::AssociationCompliance&#34; Description: &#34;A Config rule that checks whether the compliance status of the Amazon EC2 Systems Manager association compliance is COMPLIANT or NON_COMPLIANT after the association execution on the instance. The rule is compliant if the field status is COMPLIANT.&#34; Source: Owner: &#34;AWS&#34; SourceIdentifier: &#34;EC2_MANAGEDINSTANCE_ASSOCIATION_COMPLIANCE_STATUS_CHECK&#34; CloudWatchPolicy: Type: AWS::IAM::ManagedPolicy Properties: ManagedPolicyName: !Sub &#34;${ClusterFQDN}-CloudWatch&#34; Description: !Sub &#34;Policy required by Fargate to log to CloudWatch for ${ClusterFQDN}&#34; PolicyDocument: Version: &#34;2012-10-17&#34; Statement: - Effect: Allow Action: - logs:CreateLogStream - logs:CreateLogGroup - logs:DescribeLogStreams - logs:PutLogEvents Resource: &#34;*&#34; HostedZone: Type: AWS::Route53::HostedZone Properties: Name: !Ref ClusterFQDN KMSAlias: Type: AWS::KMS::Alias Properties: AliasName: !Sub &#34;alias/eks-${ClusterName}&#34; TargetKeyId: !Ref KMSKey KMSKey: Type: AWS::KMS::Key Properties: Description: !Sub &#34;KMS key for secrets related to ${ClusterFQDN}&#34; EnableKeyRotation: true PendingWindowInDays: 7 KeyPolicy: Version: &#34;2012-10-17&#34; Id: !Sub &#34;eks-key-policy-${ClusterName}&#34; Statement: - Sid: Enable IAM User Permissions Effect: Allow Principal: AWS: !Sub &#34;arn:aws:iam::${AWS::AccountId}:root&#34; Action: kms:* Resource: &#34;*&#34; - Sid: Allow use of the key Effect: Allow Principal: AWS: !Sub &#34;arn:aws:iam::${AWS::AccountId}:role/aws-service-role/autoscaling.amazonaws.com/AWSServiceRoleForAutoScaling&#34; Action: - kms:Encrypt - kms:Decrypt - kms:ReEncrypt* - kms:GenerateDataKey* - kms:DescribeKey Resource: &#34;*&#34; - Sid: Allow attachment of persistent resources Effect: Allow Principal: AWS: !Sub &#34;arn:aws:iam::${AWS::AccountId}:role/aws-service-role/autoscaling.amazonaws.com/AWSServiceRoleForAutoScaling&#34; Action: - kms:CreateGrant Resource: &#34;*&#34; Condition: Bool: kms:GrantIsForAWSResource: true EKSViewNodesAndWorkloadsPolicy: Type: AWS::IAM::ManagedPolicy Properties: ManagedPolicyName: !Sub &#34;${ClusterFQDN}-EKSViewNodesAndWorkloads&#34; Description: !Sub &#34;Policy used to view workloads running in an EKS cluster created using CAPA&#34; PolicyDocument: Version: &#34;2012-10-17&#34; Statement: - Effect: Allow Action: - eks:DescribeNodegroup - eks:ListNodegroups - eks:DescribeCluster - eks:ListClusters - eks:AccessKubernetesApi - ssm:GetParameter - eks:ListUpdates - eks:ListFargateProfiles Resource: &#34;*&#34; RecordSet: Type: AWS::Route53::RecordSet Properties: HostedZoneName: !Sub &#34;${BaseDomain}.&#34; Name: !Ref ClusterFQDN Type: NS TTL: 60 ResourceRecords: !GetAtt HostedZone.NameServers S3Policy: Type: AWS::IAM::ManagedPolicy Properties: ManagedPolicyName: !Sub &#34;${ClusterFQDN}-AmazonS3&#34; Description: !Sub &#34;Policy required by Harbor and Velero to write to S3 bucket ${ClusterFQDN}&#34; PolicyDocument: Version: &#34;2012-10-17&#34; Statement: - Effect: Allow Action: - s3:ListBucket - s3:GetBucketLocation - s3:ListBucketMultipartUploads Resource: !GetAtt S3Bucket.Arn - Effect: Allow Action: - s3:PutObject - s3:GetObject - s3:DeleteObject - s3:ListMultipartUploadParts - s3:AbortMultipartUpload Resource: !Sub &#34;arn:aws:s3:::${ClusterFQDN}/*&#34; S3Bucket: Type: AWS::S3::Bucket Properties: AccessControl: Private BucketName: !Sub &#34;${ClusterFQDN}&#34; BucketEncryption: ServerSideEncryptionConfiguration: - ServerSideEncryptionByDefault: SSEAlgorithm: AES256 SecretsManagerMySecret: Type: AWS::SecretsManager::Secret Properties: Name: !Sub &#34;${ClusterFQDN}-MySecret&#34; Description: My Secret GenerateSecretString: SecretStringTemplate: &#34;{\&#34;username\&#34;: \&#34;Administrator\&#34;}&#34; GenerateStringKey: password PasswordLength: 32 KmsKeyId: !Ref KMSKey SecretsManagerMySecret2: Type: AWS::SecretsManager::Secret Properties: Name: !Sub &#34;${ClusterFQDN}-MySecret2&#34; Description: My Secret2 GenerateSecretString: SecretStringTemplate: &#34;{\&#34;username\&#34;: \&#34;Administrator2\&#34;}&#34; GenerateStringKey: password PasswordLength: 32 KmsKeyId: !Ref KMSKey UserMyUser1: Type: AWS::IAM::User Properties: UserName: !Sub &#34;myuser1-${ClusterName}&#34; Policies: - PolicyName: !Sub &#34;myuser1-${ClusterName}-policy&#34; PolicyDocument: Version: &#34;2012-10-17&#34; Statement: - Sid: AllowAssumeOrganizationAccountRole Effect: Allow Action: sts:AssumeRole Resource: !GetAtt RoleMyUser1.Arn AccessKeyMyUser1: Type: AWS::IAM::AccessKey Properties: UserName: !Ref UserMyUser1 RoleMyUser1: Type: AWS::IAM::Role Properties: Description: !Sub &#34;IAM role for the myuser1-${ClusterName} user&#34; RoleName: !Sub &#34;myuser1-${ClusterName}&#34; AssumeRolePolicyDocument: Version: 2012-10-17 Statement: - Effect: Allow Principal: AWS: !Sub &#34;arn:aws:iam::${AWS::AccountId}:root&#34; Action: sts:AssumeRole UserMyUser2: Type: AWS::IAM::User Properties: UserName: !Sub &#34;myuser2-${ClusterName}&#34; Policies: - PolicyName: !Sub &#34;myuser2-${ClusterName}-policy&#34; PolicyDocument: Version: &#34;2012-10-17&#34; Statement: - Sid: AllowAssumeOrganizationAccountRole Effect: Allow Action: sts:AssumeRole Resource: !GetAtt RoleMyUser2.Arn AccessKeyMyUser2: Type: AWS::IAM::AccessKey Properties: UserName: !Ref UserMyUser2 RoleMyUser2: Type: AWS::IAM::Role Properties: Description: !Sub &#34;IAM role for the myuser2-${ClusterName} user&#34; RoleName: !Sub &#34;myuser2-${ClusterName}&#34; AssumeRolePolicyDocument: Version: 2012-10-17 Statement: - Effect: Allow Principal: AWS: !Sub &#34;arn:aws:iam::${AWS::AccountId}:root&#34; Action: sts:AssumeRole Outputs: CloudWatchPolicyArn: Description: The ARN of the created CloudWatchPolicy Value: !Ref CloudWatchPolicy Export: Name: Fn::Sub: &#34;${AWS::StackName}-CloudWatchPolicyArn&#34; KMSKeyArn: Description: The ARN of the created KMS Key to encrypt EKS related services Value: !GetAtt KMSKey.Arn Export: Name: Fn::Sub: &#34;${AWS::StackName}-KMSKeyArn&#34; KMSKeyId: Description: The ID of the created KMS Key to encrypt EKS related services Value: !Ref KMSKey Export: Name: Fn::Sub: &#34;${AWS::StackName}-KMSKeyId&#34; HostedZoneArn: Description: The ARN of the created Route53 Zone for K8s cluster Value: !Ref HostedZone Export: Name: Fn::Sub: &#34;${AWS::StackName}-HostedZoneArn&#34; S3PolicyArn: Description: The ARN of the created AmazonS3 policy Value: !Ref S3Policy Export: Name: Fn::Sub: &#34;${AWS::StackName}-S3PolicyArn&#34; RoleMyUser1Arn: Description: The ARN of the MyUser1 IAM Role Value: !GetAtt RoleMyUser1.Arn Export: Name: Fn::Sub: &#34;${AWS::StackName}-RoleMyUser1Arn&#34; AccessKeyMyUser1: Description: The AccessKey for MyUser1 user Value: !Ref AccessKeyMyUser1 Export: Name: Fn::Sub: &#34;${AWS::StackName}-AccessKeyMyUser1&#34; SecretAccessKeyMyUser1: Description: The SecretAccessKey for MyUser1 user Value: !GetAtt AccessKeyMyUser1.SecretAccessKey Export: Name: Fn::Sub: &#34;${AWS::StackName}-SecretAccessKeyMyUser